#include<bits/stdc++.h>
using namespace std;
int n, m;
int a[1001][1001];
bool b[1001][1001];
int ans = 0;


int main() {
	cin >> n >> m;
	for (int i = 1; i <= n ; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> b[i][j];
			if (b[i][j]) a[i][j] = min(min(a[i][j - 1], a[i - 1][j]), a[i - 1][j - 1]) + 1;
			ans=max(ans,a[i][j]);
		}
	}cout<<ans;
	return 0;
}
